package com.example.myapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity

class DeepLinkHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent) // Update the activity's intent
        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent?) {
        val appLinkData: Uri? = intent?.data
        if (appLinkData != null) {
            val host: String? = appLinkData.host
            val pathSegments: List<String> = appLinkData.pathSegments

            Log.d("DeepLinkHandler", "Received Deep Link: $appLinkData")
            Log.d("DeepLinkHandler", "Host: $host")
            Log.d("DeepLinkHandler", "Path Segments: $pathSegments")

            when (host) {
                "profile" -> {
                    if (pathSegments.isNotEmpty()) {
                        val profileId = pathSegments[0]
                        navigateToProfile(profileId)
                    } else {
                        Log.w("DeepLinkHandler", "Profile deep link received without ID: $appLinkData")
                        navigateToMain()
                    }
                }
                "payment" -> {
                    if (pathSegments.isNotEmpty() && pathSegments[0] == "confirm") {
                        navigateToPaymentConfirm()
                    } else {
                        Log.w("DeepLinkHandler", "Payment deep link received with unhandled path: $appLinkData")
                        navigateToMain()
                    }
                }
                else -> {
                    Log.w("DeepLinkHandler", "Unhandled deep link host: $host for URI: $appLinkData")
                    navigateToMain()
                }
            }
        } else {
            Log.w("DeepLinkHandler", "DeepLinkHandlerActivity started with no deep link data.")
            navigateToMain()
        }
        finish() // Finish this activity to avoid it remaining in the back stack
    }

    private fun navigateToProfile(profileId: String) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra("profileId", profileId)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }

    private fun navigateToPaymentConfirm() {
        val intent = Intent(this, PaymentActivity::class.java).apply {
            putExtra("action", "confirm") // Or any specific data
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }
}

